import{_ as e,o as a,c as i,ag as n}from"./chunks/framework.Vng7Hdlh.js";const d=JSON.parse('{"title":"SMART Apps Management","description":"","frontmatter":{},"headers":[],"relativePath":"admin-ui/smart-apps.md","filePath":"admin-ui/smart-apps.md"}'),o={name:"admin-ui/smart-apps.md"};function r(s,t,l,c,g,p){return a(),i("div",null,[...t[0]||(t[0]=[n('<h1 id="smart-apps-management" tabindex="-1">SMART Apps Management <a class="header-anchor" href="#smart-apps-management" aria-label="Permalink to &quot;SMART Apps Management&quot;">​</a></h1><p>The SMART Apps section provides comprehensive tools for registering, configuring, and managing SMART on FHIR applications within your healthcare ecosystem. This includes application registration, scope configuration, launch context setup, and ongoing management.</p><h2 id="📱-smart-application-overview" tabindex="-1">📱 SMART Application Overview <a class="header-anchor" href="#📱-smart-application-overview" aria-label="Permalink to &quot;📱 SMART Application Overview&quot;">​</a></h2><h3 id="application-types" tabindex="-1">Application Types <a class="header-anchor" href="#application-types" aria-label="Permalink to &quot;Application Types&quot;">​</a></h3><p>The platform supports various SMART application types:</p><ul><li><strong>📱 Patient-Facing Apps</strong>: Consumer health applications</li><li><strong>👨‍⚕️ Provider Apps</strong>: Clinical decision support tools</li><li><strong>🏥 EHR Integrated Apps</strong>: Deeply integrated clinical tools</li><li><strong>🔬 Research Apps</strong>: Clinical research and analytics tools</li><li><strong>🤖 Agent Apps</strong>: Autonomous AI-powered applications</li><li><strong>🔧 Backend Services</strong>: Server-to-server integrations</li></ul><h3 id="launch-types" tabindex="-1">Launch Types <a class="header-anchor" href="#launch-types" aria-label="Permalink to &quot;Launch Types&quot;">​</a></h3><ul><li><strong>📋 EHR Launch</strong>: Applications launched from within EHR</li><li><strong>🌐 Standalone Launch</strong>: Independent application launch</li><li><strong>🔗 Backend Services</strong>: Server-to-server authentication</li><li><strong>🤖 Agent Launch</strong>: Autonomous agent initialization</li></ul><h2 id="📝-application-registration" tabindex="-1">📝 Application Registration <a class="header-anchor" href="#📝-application-registration" aria-label="Permalink to &quot;📝 Application Registration&quot;">​</a></h2><h3 id="basic-application-information" tabindex="-1">Basic Application Information <a class="header-anchor" href="#basic-application-information" aria-label="Permalink to &quot;Basic Application Information&quot;">​</a></h3><h4 id="application-details" tabindex="-1">Application Details <a class="header-anchor" href="#application-details" aria-label="Permalink to &quot;Application Details&quot;">​</a></h4><ul><li><strong>📛 App Name</strong>: Human-readable application name</li><li><strong>🔗 Client ID</strong>: Unique application identifier</li><li><strong>📄 Description</strong>: Detailed application description</li><li><strong>🏢 Publisher</strong>: Organization or individual publishing app</li><li><strong>📞 Contact</strong>: Support contact information</li><li><strong>🌐 Homepage</strong>: Application homepage URL</li></ul><h4 id="technical-configuration" tabindex="-1">Technical Configuration <a class="header-anchor" href="#technical-configuration" aria-label="Permalink to &quot;Technical Configuration&quot;">​</a></h4><ul><li><strong>🔄 Redirect URIs</strong>: Valid OAuth callback URLs</li><li><strong>📡 Launch URIs</strong>: SMART launch endpoint URLs</li><li><strong>🔐 Client Type</strong>: Public, confidential, or backend service</li><li><strong>🎯 Grant Types</strong>: Supported OAuth 2.0 grant types</li><li><strong>⏰ Token Lifetimes</strong>: Access and refresh token durations</li></ul><h3 id="application-categories" tabindex="-1">Application Categories <a class="header-anchor" href="#application-categories" aria-label="Permalink to &quot;Application Categories&quot;">​</a></h3><h4 id="clinical-categories" tabindex="-1">Clinical Categories <a class="header-anchor" href="#clinical-categories" aria-label="Permalink to &quot;Clinical Categories&quot;">​</a></h4><ul><li><strong>🫀 Cardiology</strong>: Heart and cardiovascular applications</li><li><strong>🧠 Neurology</strong>: Neurological and mental health tools</li><li><strong>🩺 Primary Care</strong>: General practice and family medicine</li><li><strong>🏥 Emergency</strong>: Emergency department and urgent care</li><li><strong>💊 Pharmacy</strong>: Medication management and dispensing</li><li><strong>🔬 Laboratory</strong>: Lab results and diagnostic tools</li><li><strong>📊 Analytics</strong>: Population health and quality metrics</li></ul><h4 id="functional-categories" tabindex="-1">Functional Categories <a class="header-anchor" href="#functional-categories" aria-label="Permalink to &quot;Functional Categories&quot;">​</a></h4><ul><li><strong>📊 Clinical Decision Support</strong>: Evidence-based recommendations</li><li><strong>📱 Patient Engagement</strong>: Patient portal and communication</li><li><strong>📈 Population Health</strong>: Public health and epidemiology</li><li><strong>🔍 Quality Measurement</strong>: Healthcare quality assessment</li><li><strong>📋 Documentation</strong>: Clinical documentation and notes</li><li><strong>🏥 Workflow</strong>: Clinical workflow optimization</li></ul><h2 id="🎯-scope-configuration" tabindex="-1">🎯 Scope Configuration <a class="header-anchor" href="#🎯-scope-configuration" aria-label="Permalink to &quot;🎯 Scope Configuration&quot;">​</a></h2><h3 id="fhir-resource-scopes" tabindex="-1">FHIR Resource Scopes <a class="header-anchor" href="#fhir-resource-scopes" aria-label="Permalink to &quot;FHIR Resource Scopes&quot;">​</a></h3><p>Configure granular access to FHIR resources:</p><h4 id="patient-context-scopes-patient" tabindex="-1">Patient Context Scopes (<code>patient/</code>) <a class="header-anchor" href="#patient-context-scopes-patient" aria-label="Permalink to &quot;Patient Context Scopes (`patient/`)&quot;">​</a></h4><ul><li><strong>patient/Patient.read</strong>: Read patient demographics</li><li><strong>patient/Observation.read</strong>: Access patient observations</li><li><strong>patient/MedicationRequest.read</strong>: View medication orders</li><li><strong>patient/DiagnosticReport.read</strong>: Access diagnostic reports</li><li><strong>patient/Condition.read</strong>: View patient conditions</li><li><strong>patient/Procedure.read</strong>: Access procedure records</li></ul><h4 id="user-context-scopes-user" tabindex="-1">User Context Scopes (<code>user/</code>) <a class="header-anchor" href="#user-context-scopes-user" aria-label="Permalink to &quot;User Context Scopes (`user/`)&quot;">​</a></h4><ul><li><strong>user/Patient.read</strong>: Read patients accessible to user</li><li><strong>user/Practitioner.read</strong>: Access practitioner information</li><li><strong>user/Organization.read</strong>: View organization details</li><li><strong>user/Location.read</strong>: Access location information</li></ul><h4 id="system-context-scopes-system" tabindex="-1">System Context Scopes (<code>system/</code>) <a class="header-anchor" href="#system-context-scopes-system" aria-label="Permalink to &quot;System Context Scopes (`system/`)&quot;">​</a></h4><ul><li><strong>system/Patient.read</strong>: System-wide patient access</li><li><strong>system/Observation.cruds</strong>: Full observation CRUD operations</li><li><strong>system/Bundle.read</strong>: Access to FHIR bundles</li><li><strong>system/*.read</strong>: Read access to all resources</li></ul><h4 id="agent-context-scopes-agent" tabindex="-1">Agent Context Scopes (<code>agent/</code>) <a class="header-anchor" href="#agent-context-scopes-agent" aria-label="Permalink to &quot;Agent Context Scopes (`agent/`)&quot;">​</a></h4><ul><li><strong>agent/Patient.read</strong>: Autonomous patient data access</li><li><strong>agent/Observation.write</strong>: AI-generated observations</li><li><strong>agent/ClinicalImpression.cruds</strong>: AI clinical assessments</li><li><strong>agent/Device.read</strong>: Access to device information</li></ul><h3 id="custom-scope-templates" tabindex="-1">Custom Scope Templates <a class="header-anchor" href="#custom-scope-templates" aria-label="Permalink to &quot;Custom Scope Templates&quot;">​</a></h3><h4 id="role-based-templates" tabindex="-1">Role-Based Templates <a class="header-anchor" href="#role-based-templates" aria-label="Permalink to &quot;Role-Based Templates&quot;">​</a></h4><ul><li><strong>👨‍⚕️ Clinician Template</strong>: Standard clinical scopes</li><li><strong>👨‍💼 Administrator Template</strong>: Administrative access scopes</li><li><strong>🔬 Researcher Template</strong>: Research-appropriate data access</li><li><strong>📱 Patient Template</strong>: Patient-facing application scopes</li></ul><h4 id="specialty-templates" tabindex="-1">Specialty Templates <a class="header-anchor" href="#specialty-templates" aria-label="Permalink to &quot;Specialty Templates&quot;">​</a></h4><ul><li><strong>🫀 Cardiology Scopes</strong>: Heart-specific resource access</li><li><strong>🧠 Mental Health Scopes</strong>: Psychiatric and psychological data</li><li><strong>💊 Pharmacy Scopes</strong>: Medication-related resources</li><li><strong>🩺 Primary Care Scopes</strong>: General practice resource set</li></ul><h2 id="🚀-launch-context-configuration" tabindex="-1">🚀 Launch Context Configuration <a class="header-anchor" href="#🚀-launch-context-configuration" aria-label="Permalink to &quot;🚀 Launch Context Configuration&quot;">​</a></h2><h3 id="clinical-context-types" tabindex="-1">Clinical Context Types <a class="header-anchor" href="#clinical-context-types" aria-label="Permalink to &quot;Clinical Context Types&quot;">​</a></h3><h4 id="patient-context" tabindex="-1">Patient Context <a class="header-anchor" href="#patient-context" aria-label="Permalink to &quot;Patient Context&quot;">​</a></h4><ul><li><strong>👤 Patient Selection</strong>: Specific patient in context</li><li><strong>📊 Patient List</strong>: Cohort or population context</li><li><strong>🏥 Encounter Context</strong>: Current patient encounter</li><li><strong>📋 Episode Context</strong>: Care episode or treatment period</li></ul><h4 id="provider-context" tabindex="-1">Provider Context <a class="header-anchor" href="#provider-context" aria-label="Permalink to &quot;Provider Context&quot;">​</a></h4><ul><li><strong>👨‍⚕️ Practitioner</strong>: Current authenticated provider</li><li><strong>👥 Care Team</strong>: Multi-provider team context</li><li><strong>🏢 Organization</strong>: Healthcare organization context</li><li><strong>🏥 Location</strong>: Physical location or department</li></ul><h4 id="workflow-context" tabindex="-1">Workflow Context <a class="header-anchor" href="#workflow-context" aria-label="Permalink to &quot;Workflow Context&quot;">​</a></h4><ul><li><strong>📋 Order Entry</strong>: Medication or diagnostic ordering</li><li><strong>📊 Results Review</strong>: Lab or diagnostic result review</li><li><strong>📝 Documentation</strong>: Clinical note and documentation</li><li><strong>🔍 Research</strong>: Clinical research and analytics</li></ul><h3 id="launch-context-templates" tabindex="-1">Launch Context Templates <a class="header-anchor" href="#launch-context-templates" aria-label="Permalink to &quot;Launch Context Templates&quot;">​</a></h3><h4 id="pre-configured-contexts" tabindex="-1">Pre-configured Contexts <a class="header-anchor" href="#pre-configured-contexts" aria-label="Permalink to &quot;Pre-configured Contexts&quot;">​</a></h4><ul><li><strong>🏥 Inpatient Workflow</strong>: Hospital-based patient care</li><li><strong>🏠 Ambulatory Care</strong>: Outpatient clinic workflow</li><li><strong>🚨 Emergency Department</strong>: ED-specific rapid workflow</li><li><strong>💊 Pharmacy</strong>: Medication management workflow</li><li><strong>🔬 Laboratory</strong>: Lab-focused diagnostic workflow</li></ul><h4 id="custom-context-builder" tabindex="-1">Custom Context Builder <a class="header-anchor" href="#custom-context-builder" aria-label="Permalink to &quot;Custom Context Builder&quot;">​</a></h4><ul><li><strong>🎯 Context Parameters</strong>: Define custom launch parameters</li><li><strong>📊 Data Elements</strong>: Specify required context data</li><li><strong>🔗 Context Linking</strong>: Link contexts across applications</li><li><strong>⚙️ Dynamic Context</strong>: Runtime context resolution</li></ul><h2 id="📊-application-monitoring" tabindex="-1">📊 Application Monitoring <a class="header-anchor" href="#📊-application-monitoring" aria-label="Permalink to &quot;📊 Application Monitoring&quot;">​</a></h2><h3 id="usage-analytics" tabindex="-1">Usage Analytics <a class="header-anchor" href="#usage-analytics" aria-label="Permalink to &quot;Usage Analytics&quot;">​</a></h3><p>Track application performance and usage:</p><h4 id="launch-metrics" tabindex="-1">Launch Metrics <a class="header-anchor" href="#launch-metrics" aria-label="Permalink to &quot;Launch Metrics&quot;">​</a></h4><ul><li><strong>🚀 Launch Count</strong>: Total application launches</li><li><strong>✅ Success Rate</strong>: Successful launch percentage</li><li><strong>⏱️ Launch Time</strong>: Average time to successful launch</li><li><strong>❌ Error Rate</strong>: Failed launch analysis</li></ul><h4 id="user-engagement" tabindex="-1">User Engagement <a class="header-anchor" href="#user-engagement" aria-label="Permalink to &quot;User Engagement&quot;">​</a></h4><ul><li><strong>👥 Active Users</strong>: Unique users per time period</li><li><strong>⏰ Session Duration</strong>: Average user session length</li><li><strong>🔄 Return Rate</strong>: User retention metrics</li><li><strong>📊 Feature Usage</strong>: Most/least used features</li></ul><h4 id="performance-metrics" tabindex="-1">Performance Metrics <a class="header-anchor" href="#performance-metrics" aria-label="Permalink to &quot;Performance Metrics&quot;">​</a></h4><ul><li><strong>⚡ Response Time</strong>: API response performance</li><li><strong>📈 Throughput</strong>: Requests per second</li><li><strong>💾 Data Volume</strong>: FHIR resource access volume</li><li><strong>🔄 Token Usage</strong>: OAuth token refresh patterns</li></ul><h3 id="error-tracking" tabindex="-1">Error Tracking <a class="header-anchor" href="#error-tracking" aria-label="Permalink to &quot;Error Tracking&quot;">​</a></h3><ul><li><strong>🚨 Authorization Errors</strong>: OAuth flow failures</li><li><strong>🔐 Permission Errors</strong>: Scope violation attempts</li><li><strong>🌐 Network Errors</strong>: Connectivity issues</li><li><strong>⚙️ Application Errors</strong>: App-specific error patterns</li></ul><h2 id="🔐-security-and-compliance" tabindex="-1">🔐 Security and Compliance <a class="header-anchor" href="#🔐-security-and-compliance" aria-label="Permalink to &quot;🔐 Security and Compliance&quot;">​</a></h2><h3 id="security-features" tabindex="-1">Security Features <a class="header-anchor" href="#security-features" aria-label="Permalink to &quot;Security Features&quot;">​</a></h3><h4 id="oauth-2-0-security" tabindex="-1">OAuth 2.0 Security <a class="header-anchor" href="#oauth-2-0-security" aria-label="Permalink to &quot;OAuth 2.0 Security&quot;">​</a></h4><ul><li><strong>🔒 PKCE</strong>: Proof Key for Code Exchange</li><li><strong>🛡️ State Parameter</strong>: CSRF protection</li><li><strong>⏰ Token Expiration</strong>: Configurable token lifetimes</li><li><strong>🔄 Refresh Tokens</strong>: Secure token renewal</li></ul><h4 id="application-validation" tabindex="-1">Application Validation <a class="header-anchor" href="#application-validation" aria-label="Permalink to &quot;Application Validation&quot;">​</a></h4><ul><li><strong>✅ URI Validation</strong>: Redirect and launch URI verification</li><li><strong>🔐 Client Authentication</strong>: Secure client credential management</li><li><strong>📱 App Attestation</strong>: Mobile app integrity verification</li><li><strong>🛡️ Scope Validation</strong>: Requested scope verification</li></ul><h3 id="compliance-support" tabindex="-1">Compliance Support <a class="header-anchor" href="#compliance-support" aria-label="Permalink to &quot;Compliance Support&quot;">​</a></h3><ul><li><strong>📋 HIPAA Compliance</strong>: Healthcare data protection</li><li><strong>🌍 GDPR Support</strong>: Data privacy compliance</li><li><strong>📊 Audit Logging</strong>: Comprehensive access logging</li><li><strong>🔍 Regular Reviews</strong>: Periodic security assessments</li></ul><h2 id="🔧-application-management" tabindex="-1">🔧 Application Management <a class="header-anchor" href="#🔧-application-management" aria-label="Permalink to &quot;🔧 Application Management&quot;">​</a></h2><h3 id="lifecycle-management" tabindex="-1">Lifecycle Management <a class="header-anchor" href="#lifecycle-management" aria-label="Permalink to &quot;Lifecycle Management&quot;">​</a></h3><h4 id="application-states" tabindex="-1">Application States <a class="header-anchor" href="#application-states" aria-label="Permalink to &quot;Application States&quot;">​</a></h4><ul><li><strong>🟢 Active</strong>: Application available for use</li><li><strong>🟡 Testing</strong>: Development/testing phase</li><li><strong>🔴 Suspended</strong>: Temporarily disabled</li><li><strong>⚪ Retired</strong>: No longer available</li></ul><h4 id="version-management" tabindex="-1">Version Management <a class="header-anchor" href="#version-management" aria-label="Permalink to &quot;Version Management&quot;">​</a></h4><ul><li><strong>📊 Version Tracking</strong>: Multiple application versions</li><li><strong>🔄 Update Management</strong>: Controlled version updates</li><li><strong>📈 Migration Support</strong>: Version transition assistance</li><li><strong>🔙 Rollback Capability</strong>: Revert to previous versions</li></ul><h3 id="configuration-management" tabindex="-1">Configuration Management <a class="header-anchor" href="#configuration-management" aria-label="Permalink to &quot;Configuration Management&quot;">​</a></h3><ul><li><strong>⚙️ Environment Config</strong>: Dev, test, production settings</li><li><strong>🔧 Feature Flags</strong>: Enable/disable application features</li><li><strong>🎛️ Parameter Tuning</strong>: Runtime configuration changes</li><li><strong>📊 A/B Testing</strong>: Feature testing and validation</li></ul><h2 id="🔗-integration-capabilities" tabindex="-1">🔗 Integration Capabilities <a class="header-anchor" href="#🔗-integration-capabilities" aria-label="Permalink to &quot;🔗 Integration Capabilities&quot;">​</a></h2><h3 id="ehr-integration" tabindex="-1">EHR Integration <a class="header-anchor" href="#ehr-integration" aria-label="Permalink to &quot;EHR Integration&quot;">​</a></h3><ul><li><strong>🏥 Epic Integration</strong>: Epic-specific launch configurations</li><li><strong>🔗 Cerner Integration</strong>: Cerner-optimized settings</li><li><strong>⚕️ Allscripts</strong>: Allscripts-compatible configuration</li><li><strong>🌐 Generic SMART</strong>: Standards-compliant integration</li></ul><h3 id="third-party-services" tabindex="-1">Third-Party Services <a class="header-anchor" href="#third-party-services" aria-label="Permalink to &quot;Third-Party Services&quot;">​</a></h3><ul><li><strong>🔐 Identity Providers</strong>: External authentication</li><li><strong>📊 Analytics Services</strong>: Usage tracking integration</li><li><strong>☁️ Cloud Services</strong>: Cloud platform integration</li><li><strong>🔔 Notification Services</strong>: Push notification support</li></ul><h2 id="📱-mobile-application-support" tabindex="-1">📱 Mobile Application Support <a class="header-anchor" href="#📱-mobile-application-support" aria-label="Permalink to &quot;📱 Mobile Application Support&quot;">​</a></h2><h3 id="mobile-specific-features" tabindex="-1">Mobile-Specific Features <a class="header-anchor" href="#mobile-specific-features" aria-label="Permalink to &quot;Mobile-Specific Features&quot;">​</a></h3><ul><li><strong>📱 App Store Links</strong>: iOS/Android app store integration</li><li><strong>🔗 Deep Linking</strong>: Native app launch support</li><li><strong>📲 Push Notifications</strong>: Mobile notification delivery</li><li><strong>🔒 Certificate Pinning</strong>: Enhanced mobile security</li></ul><h3 id="progressive-web-apps-pwa" tabindex="-1">Progressive Web Apps (PWA) <a class="header-anchor" href="#progressive-web-apps-pwa" aria-label="Permalink to &quot;Progressive Web Apps (PWA)&quot;">​</a></h3><ul><li><strong>🌐 Web App Manifest</strong>: PWA configuration</li><li><strong>⚡ Service Workers</strong>: Offline capability</li><li><strong>🏠 Home Screen</strong>: Install to home screen</li><li><strong>📱 Native Experience</strong>: App-like behavior</li></ul><h2 id="🎯-best-practices" tabindex="-1">🎯 Best Practices <a class="header-anchor" href="#🎯-best-practices" aria-label="Permalink to &quot;🎯 Best Practices&quot;">​</a></h2><h3 id="application-design" tabindex="-1">Application Design <a class="header-anchor" href="#application-design" aria-label="Permalink to &quot;Application Design&quot;">​</a></h3><ol><li><strong>🎯 Scope Minimization</strong>: Request only necessary permissions</li><li><strong>🔒 Security First</strong>: Implement strong security measures</li><li><strong>👥 User Experience</strong>: Prioritize intuitive interface design</li><li><strong>📊 Performance</strong>: Optimize for speed and efficiency</li></ol><h3 id="launch-context" tabindex="-1">Launch Context <a class="header-anchor" href="#launch-context" aria-label="Permalink to &quot;Launch Context&quot;">​</a></h3><ol><li><strong>🎯 Context Relevance</strong>: Ensure context matches workflow</li><li><strong>⚡ Fast Loading</strong>: Minimize context resolution time</li><li><strong>🔄 Context Persistence</strong>: Maintain context across sessions</li><li><strong>📊 Context Validation</strong>: Verify context accuracy</li></ol><h3 id="ongoing-management" tabindex="-1">Ongoing Management <a class="header-anchor" href="#ongoing-management" aria-label="Permalink to &quot;Ongoing Management&quot;">​</a></h3><ol><li><strong>📊 Monitor Usage</strong>: Track application performance</li><li><strong>🔄 Regular Updates</strong>: Keep applications current</li><li><strong>🛡️ Security Reviews</strong>: Periodic security assessments</li><li><strong>👥 User Feedback</strong>: Collect and act on user input</li></ol><p>The SMART Apps management system provides comprehensive tools for healthcare application lifecycle management, ensuring secure, compliant, and efficient integration within the healthcare ecosystem.</p><h2 id="sub-tabs" tabindex="-1">Sub-Tabs <a class="header-anchor" href="#sub-tabs" aria-label="Permalink to &quot;Sub-Tabs&quot;">​</a></h2><p>The SMART Apps page contains three sub-tabs:</p><h3 id="registered-apps" tabindex="-1">Registered Apps <a class="header-anchor" href="#registered-apps" aria-label="Permalink to &quot;Registered Apps&quot;">​</a></h3><p>The main view for managing manually registered SMART client applications (documented above).</p><h3 id="app-store" tabindex="-1">App Store <a class="header-anchor" href="#app-store" aria-label="Permalink to &quot;App Store&quot;">​</a></h3><p>Controls the visibility and publication of SMART apps:</p><table tabindex="0"><thead><tr><th>Action</th><th>Description</th></tr></thead><tbody><tr><td><strong>Publish</strong></td><td>Make an app available in the app store catalog</td></tr><tr><td><strong>Unpublish</strong></td><td>Remove an app from the catalog</td></tr><tr><td><strong>Hide</strong></td><td>Hide an app from the catalog without removing it</td></tr><tr><td><strong>Show</strong></td><td>Restore visibility of a hidden app</td></tr></tbody></table><p>API endpoints: <code>GET /admin/app-store/</code>, <code>POST /admin/app-store/publish</code>, <code>POST /admin/app-store/:appId/hide</code>, <code>POST /admin/app-store/:appId/show</code>, <code>POST /admin/app-store/:appId/unpublish</code>.</p><h3 id="dynamic-client-registration" tabindex="-1">Dynamic Client Registration <a class="header-anchor" href="#dynamic-client-registration" aria-label="Permalink to &quot;Dynamic Client Registration&quot;">​</a></h3><p>Manages RFC 7591 Dynamic Client Registration settings:</p><ul><li><strong>View settings</strong> — current DCR policy configuration</li><li><strong>Update settings</strong> — modify registration requirements and defaults</li><li><strong>Reset to defaults</strong> — restore factory DCR settings</li></ul><p>API endpoints: <code>GET /admin/client-registration/settings</code>, <code>PUT /admin/client-registration/settings</code>, <code>POST /admin/client-registration/reset-defaults</code>.</p>',105)])])}const h=e(o,[["render",r]]);export{d as __pageData,h as default};
